@Test public void handlesCommentWithoutClosingBracket() {
    String html = "<body>One</body><!-- comment";
    Document doc = Jsoup.parse(html, "", Parser.xmlParser());
    assertEquals("<body> One </body> <!-- comment -->", StringUtil.normaliseWhitespace(doc.outerHtml()));
    assertEquals("#comment", doc.childNode(1).nodeName());
    assertEquals(" comment", ((Comment)doc.childNode(1)).getData());
}

@Test public void handlesMultipleCommentsAndDeclarations() {
    String html = "<?xml version='1.0'?><!-- first --><!-- second --><root/>";
    Document doc = Jsoup.parse(html, "", Parser.xmlParser());
    assertEquals("<?xml version='1.0'?> <!-- first --> <!-- second --> <root />".
        StringUtil.normaliseWhitespace(doc.outerHtml()));
    assertEquals("#declaration", doc.childNode(0).nodeName());
    assertEquals("#comment", doc.childNode(1).nodeName());
    assertEquals(" first ", ((Comment)doc.childNode(1)).getData());
    assertEquals("#comment", doc.childNode(2).nodeName());
    assertEquals(" second ", ((Comment)doc.childNode(2)).getData());
}

@Test public void handlesEmptyComment() {
    String html = "<root><!--  --></root>";
    Document doc = Jsoup.parse(html, "", Parser.xmlParser());
    assertEquals("<root> <!--  --> </root>", StringUtil.normaliseWhitespace(doc.outerHtml()));
    assertEquals(1, doc.childNode(0).childNodes().size());
    assertEquals("#comment", doc.childNode(0).childNode(0).nodeName());
    assertEquals("  ", ((Comment)doc.childNode(0).childNode(0)).getData());
}
